using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---

var researchTools = new ResearchTools();
var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.TakeNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// --- Create the agent ---

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Tools = [.. tools],
            Temperature = 0f,
            MaxOutputTokens = 2048,
        },
    });

// --- Prompt the user ---

Console.WriteLine("╔══════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent          ║");
Console.WriteLine("╚══════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));
Console.WriteLine();

// --- Run the agent with streaming output ---

var prompt = $"""
    Research the following topic thoroughly: "{topic}"

    Follow these steps:
    1. Search the web for key information about this topic using multiple search queries.
    2. Take notes on the most important findings as you go.
    3. Review your notes, then provide a comprehensive summary with:
       - An overview of the topic
       - Key facts and details
       - Recent developments (if any)
       - Sources of information
    """;

await foreach (var update in agent.RunStreamingAsync(prompt))
{
    Console.Write(update.Text);
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine("Research complete.");

// ──────────────────────────────────────────────────
// Tool implementations
// ──────────────────────────────────────────────────

sealed partial class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    [Description("Search the web for information on a topic. Returns relevant search result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0 (compatible)");

            var response = await _httpClient.SendAsync(request);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync();

            // Extract result snippets from DuckDuckGo HTML
            var results = new List<string>();

            foreach (var match in SnippetRegex().Matches(html).Cast<Match>().Take(5))
            {
                var text = HtmlTagRegex().Replace(match.Groups[1].Value, "").Trim();
                text = WebUtility.HtmlDecode(text);
                if (!string.IsNullOrWhiteSpace(text))
                {
                    results.Add(text);
                }
            }

            return results.Count > 0
                ? $"Search results for \"{query}\":\n\n"
                  + string.Join("\n\n", results.Select((r, i) => $"{i + 1}. {r}"))
                : $"No results found for \"{query}\". Try a different search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try rephrasing the query.";
        }
    }

    [Description("Save a research note about an important finding.")]
    public string TakeNote(
        [Description("The content of the note to save")] string content)
    {
        _notes.Add(content);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all research notes taken so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes taken yet.";
        }

        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }

    [GeneratedRegex("""<a class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();
}

