 sealed partial class ResearchTools
 {
     private readonly List<string> _notes = [];
     private readonly HttpClient _httpClient = new();

     [Description("Search the web for information on a topic. Returns relevant search result snippets.")]
     public async Task<string> SearchWeb(
         [Description("The search query string")] string query)
     {
         try
         {
             var encoded = WebUtility.UrlEncode(query);
             var url = $"https://html.duckduckgo.com/html/?q={encoded}";

             using var request = new HttpRequestMessage(HttpMethod.Get, url);
             request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0 (compatible)");

             var response = await _httpClient.SendAsync(request);
             response.EnsureSuccessStatusCode();
             var html = await response.Content.ReadAsStringAsync();

             // Extract result snippets from DuckDuckGo HTML
             var results = new List<string>();

             foreach (var match in SnippetRegex().Matches(html).Cast<Match>().Take(5))
             {
                 var text = HtmlTagRegex().Replace(match.Groups[1].Value, "").Trim();
                 text = WebUtility.HtmlDecode(text);
                 if (!string.IsNullOrWhiteSpace(text))
                 {
                     results.Add(text);
                 }
             }

             return results.Count > 0
                 ? $"Search results for \"{query}\":\n\n"
                   + string.Join("\n\n", results.Select((r, i) => $"{i + 1}. {r}"))
                 : $"No results found for \"{query}\". Try a different search query.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try rephrasing the query.";
         }
     }

     [Description("Save a research note about an important finding.")]
     public string TakeNote(
         [Description("The content of the note to save")] string content)
     {
         _notes.Add(content);
         return $"Note #{_notes.Count} saved.";
     }

     [Description("Retrieve all research notes taken so far.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
         {
             return "No notes taken yet.";
         }

         return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
     }

     [GeneratedRegex("""<a class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
     private static partial Regex SnippetRegex();

